from source import longest_common_subsequence


def test_match_advances_both_strings():
    a, b = 'AGCAT', 'GAC'
    result = longest_common_subsequence(a, b)

    def is_subsequence(s, string):
        it = iter(string)
        return all(c in it for c in s)

    assert len(result) == 2 and is_subsequence(result, a) and is_subsequence(result, b), (
        f"longest_common_subsequence({a!r}, {b!r}) returned {result!r} (len={len(result)}), "
        f"but the correct LCS has length 2 (e.g. 'GA', 'AC', or 'GC'). "
        f"Bug: on a match, b is not advanced, so b[0] can be reused across multiple recursive calls."
    )
